    def update(self, id, x1=None, x2=None, y1=None, y2=None):
        try:
            with sq.connect(self.db_name) as con:
                cur = con.cursor()
                
                updates = []
                params = []
                
                if x1 is not None:
                    updates.append("X1 = ?")
                    params.append(x1)
                if x2 is not None:
                    updates.append("X2 = ?")
                    params.append(x2)
                if y1 is not None:
                    updates.append("Y1 = ?")
                    params.append(y1)
                if y2 is not None:
                    updates.append("Y2 = ?")
                    params.append(y2)
                
                if not updates:
                    print("Нет данных для обновления")
                    return
                query = f"UPDATE RECTANGLES SET {', '.join(updates)} WHERE ID = ?"
                params.append(id)
                
                cur.execute(query, params)
                con.commit()
        except Exception as e:
            print(f'Ошибка БД при обновлении: {e}')
            
